import React from 'react';
import FigmaChat from '../components/FigmaChat';
import '../styles/figma-design.css';

export default function FigmaHome() {
    return (
        <div style={{ 
            background: '#0F0F0F', 
            minHeight: '100vh',
            paddingTop: '80px'
        }}>
            {/* Логотип */}
            <div style={{
                position: 'fixed',
                top: '20px',
                left: '24px',
                zIndex: 50
            }}>
                <div style={{
                    width: '40px',
                    height: '40px',
                    background: 'linear-gradient(135deg, #8B5CF6 0%, #EC4899 100%)',
                    borderRadius: '12px'
                }}></div>
            </div>

            {/* Кнопка регистрации */}
            <div style={{
                position: 'fixed',
                top: '20px',
                right: '24px',
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
                background: 'rgba(255, 255, 255, 0.1)',
                padding: '8px 16px',
                borderRadius: '30px',
                cursor: 'pointer',
                zIndex: 50
            }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                    <path d="M20 21V19C20 16.8 18.2 15 16 15H8C5.8 15 4 16.8 4 19V21" stroke="white" strokeWidth="2"/>
                    <circle cx="12" cy="7" r="4" stroke="white" strokeWidth="2"/>
                </svg>
                <p style={{ color: 'white', fontFamily: 'var(--font-family-proxima-nova)' }}>Регистрация</p>
            </div>

            {/* Видео и чат */}
            <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '0 24px' }}>
                <div style={{
                    background: '#000',
                    borderRadius: '16px',
                    overflow: 'hidden',
                    marginBottom: '24px'
                }}>
                    <video 
                        controls 
                        style={{ width: '100%', display: 'block' }}
                        poster="https://via.placeholder.com/1280x720"
                    >
                        <source src="/sample.mp4" type="video/mp4" />
                    </video>
                </div>

                <FigmaChat />
            </div>
        </div>
    );
}
